const c=document.querySelectorAll("#who"),s=document.querySelectorAll("#spend"),r=document.querySelectorAll("#admin-link"),d=document.querySelectorAll("#logout"),u=document.querySelectorAll("[data-user-name]"),f=document.querySelectorAll("[data-user-initials]");function h(t){const n=t.email||"",o=(t.name||"").trim(),i=n.split("@")[0]||n,e=o||i;let l;if(o){const a=o.split(/\s+/).filter(Boolean);l=a.length>=2?a[0][0]+a[1][0]:o.slice(0,2)}else l=i.replace(/[^a-z0-9]/gi,"").slice(0,2)||n.slice(0,2);return{display:e,initials:(l||"?").toUpperCase()}}function p(t){c.forEach(e=>{e.textContent=t.email});const{display:n,initials:o}=h(t);u.forEach(e=>{e.textContent=n}),f.forEach(e=>{e.textContent=o});let i="";if(typeof t.spent_usd=="number"){const e="$"+t.spent_usd.toFixed(2);i=t.unlimited?e+" today":e+" / $"+Number(t.budget_usd).toFixed(2)+" today"}s.forEach(e=>{e.textContent=i}),t.is_admin&&r.forEach(e=>{e.hidden=!1})}async function y(){try{const t=await fetch("/api/auth/me");if(!t.ok)return window.location.href="/login",null;const n=await t.json();return p(n),n}catch{return window.location.href="/login",null}}d.forEach(t=>{t.addEventListener("click",async()=>{try{await fetch("/api/auth/logout",{method:"POST"})}finally{window.location.href="/login"}})});y();async function m(){const t=document.getElementById("cr-chip");if(t)try{const n=await fetch("/api/cr-version");if(!n.ok)return;const{effective_date:o}=await n.json();if(!o)return;t.textContent="CR · "+o,t.title="Comprehensive Rules — effective "+o,t.hidden=!1}catch{}}m();export{y as r};
